// Artifact cleanup script with retention policies
// Supports: max age, max total size, keep-latest-N per workflow

export interface Artifact {
  name: string;
  size: number;
  createdAt: Date;
  workflowRunId: string;
}

export interface RetentionPolicy {
  maxAge?: number;
  maxTotalSize?: number;
  keepLatestN?: number;
}

export interface CleanupResult {
  toDelete: Artifact[];
  toRetain: Artifact[];
  spaceSaved: number;
  summary: {
    totalArtifacts: number;
    deleted: number;
    retained: number;
    spaceSavedBytes: number;
    spaceSavedMB: number;
  };
}

export function cleanupArtifacts(
  artifacts: Artifact[],
  policy: RetentionPolicy,
  dryRun: boolean
): CleanupResult {
  const now = new Date();
  const toDelete: Artifact[] = [];
  const toRetain: Artifact[] = [];

  // Apply max age policy
  for (const artifact of artifacts) {
    let shouldDelete = false;

    if (policy.maxAge !== undefined) {
      const age = now.getTime() - artifact.createdAt.getTime();
      if (age > policy.maxAge) {
        shouldDelete = true;
      }
    }

    if (shouldDelete) {
      toDelete.push(artifact);
    } else {
      toRetain.push(artifact);
    }
  }

  const spaceSavedBytes = toDelete.reduce((sum, a) => sum + a.size, 0);

  return {
    toDelete,
    toRetain,
    spaceSaved: spaceSavedBytes,
    summary: {
      totalArtifacts: artifacts.length,
      deleted: toDelete.length,
      retained: toRetain.length,
      spaceSavedBytes,
      spaceSavedMB: Math.round(spaceSavedBytes / (1024 * 1024) * 100) / 100,
    },
  };
}

